// hr/service/EmployeeManagementServiceImpl.java
package hr.service;

import hr.model.OperationStatus;
import hr.model.PerformanceReviewRequest;
import hr.model.SalaryUpdateRequest;
import hr.model.TerminationRequest;

import javax.jws.WebService;

@WebService(
    endpointInterface = "hr.service.EmployeeManagementService",
    serviceName = "EmployeeManagementService",
    portName = "EmployeeManagementPort",
    targetNamespace = "http://service.hr.com/"
)
public class EmployeeManagementServiceImpl implements EmployeeManagementService {

    @Override
    public OperationStatus updateSalary(SalaryUpdateRequest request) {
        if (request == null || request.getEmployeeId() == null || request.getNewSalary() <= 0) {
            return new OperationStatus(false, "Invalid salary update request. Employee ID and new salary are required.");
        }
        System.out.println("Processing Salary Update for Employee: " + request.getEmployeeId());
        System.out.println("New Salary: " + request.getNewSalary());
        System.out.println("Effective Date: " + request.getEffectiveDate());
        System.out.println("Reason: " + request.getReason());
        return new OperationStatus(true, "Salary updated successfully for employee " + request.getEmployeeId());
    }

    @Override
    public OperationStatus conductPerformanceReview(PerformanceReviewRequest request) {
        if (request == null || request.getEmployeeId() == null || request.getReviewerId() == null || request.getRating() < 1 || request.getRating() > 5) {
            return new OperationStatus(false, "Invalid performance review request. Employee ID, Reviewer ID, and a valid rating (1-5) are required.");
        }
        System.out.println("Processing Performance Review for Employee: " + request.getEmployeeId());
        System.out.println("Reviewer: " + request.getReviewerId());
        System.out.println("Review Date: " + request.getReviewDate());
        System.out.println("Rating: " + request.getRating());
        System.out.println("Comments: " + request.getComments());
        return new OperationStatus(true, "Performance review conducted successfully for employee " + request.getEmployeeId());
    }

    @Override
    public OperationStatus terminateEmployee(TerminationRequest request) {
        if (request == null || request.getEmployeeId() == null || request.getReason() == null) {
            return new OperationStatus(false, "Invalid termination request. Employee ID and reason are required.");
        }
        System.out.println("Processing Termination for Employee: " + request.getEmployeeId());
        System.out.println("Termination Date: " + request.getTerminationDate());
        System.out.println("Reason: " + request.getReason());
        System.out.println("Exit Interview Conducted: " + request.isExitInterviewConducted());
        return new OperationStatus(true, "Employee " + request.getEmployeeId() + " terminated successfully.");
    }
}


